// ╔══════════════════════════════════════════════════╗
// ║  EVEZ666 CONFIG — EDIT YOUR KEYS HERE ONCE       ║
// ║  Tap this node → edit → paste keys → save        ║
// ╚══════════════════════════════════════════════════╝

return [{json:{
  // FREE AI — get at console.groq.com (2 min, no card)
  groq:    'PASTE_GROQ_KEY_HERE',

  // FREE AI FALLBACKS (optional but recommended)
  gemini:  'PASTE_GEMINI_KEY_HERE',   // aistudio.google.com
  or_key:  'PASTE_OR_KEY_HERE',       // openrouter.ai

  // TWITTER — developer.twitter.com (free Basic plan)
  tw_bearer: '',          // TWITTER_BEARER_TOKEN
  tw_ak:     '',          // TWITTER_API_KEY
  tw_as:     '',          // TWITTER_API_SECRET
  tw_at:     '',          // TWITTER_ACCESS_TOKEN
  tw_ats:    '',          // TWITTER_ACCESS_SECRET

  // SET TO 'true' TO POST LIVE (default: preview only)
  auto_post: 'false',

  // HuggingFace — huggingface.co (free, for meme images)
  hf: '',

  // n8n API key for spawning sub-agents (n8n Settings → API)
  n8n_key:  '',
  n8n_url:  'https://evezos.app.n8n.cloud',
}}];

const slot = Math.floor(Date.now() / 14400000);
const out  = { slot, ts: new Date().toISOString() };

// 1. DuckDuckGo
try {
  const d = await $fetch('https://api.duckduckgo.com/?q=evez666+autonomous+AI+defi&format=json&no_html=1&skip_disambig=1',
    {headers:{'User-Agent':'EVEZ-OS/2.0'}});
  out.ddg = {abstract:(d.AbstractText||'').slice(0,300), related:(d.RelatedTopics||[]).slice(0,4).map(t=>(t.Text||'').slice(0,80)).filter(Boolean)};
} catch(e){out.ddg={};}

// 2. Reddit (no key)
out.reddit=[];
for(const q of ['evez666','defi autonomous agent 2026','AI meme crypto autonomous']){
  try{
    const r=await $fetch('https://www.reddit.com/search.json?q='+encodeURIComponent(q)+'&sort=hot&limit=3&t=week',
      {headers:{'User-Agent':'EVEZ-OS/2.0'}});
    (r.data&&r.data.children?r.data.children:[]).forEach(p=>
      out.reddit.push({t:(p.data.title||'').slice(0,100),s:p.data.score,r:p.data.subreddit}));
  }catch(e2){}
}
out.reddit=out.reddit.slice(0,8);

// 3. HackerNews Algolia (no key)
try{
  const hn=await $fetch('https://hn.algolia.com/api/v1/search?query=autonomous+AI+agent+DeFi&hitsPerPage=5');
  out.hn=(hn.hits||[]).map(h=>({t:(h.title||'').slice(0,100),p:h.points}));
}catch(e){out.hn=[];}

// 4. CoinGecko trending
try{
  const cg=await $fetch('https://api.coingecko.com/api/v3/search/trending');
  out.trending=(cg.coins||[]).slice(0,5).map(c=>({n:c.item.name,sym:c.item.symbol,
    chg:c.item.data&&c.item.data.price_change_percentage_24h?+c.item.data.price_change_percentage_24h.usd.toFixed(1):0}));
}catch(e){out.trending=[];}

// 5. CoinGecko global market
try{
  const gm=await $fetch('https://api.coingecko.com/api/v3/global');
  const gd=gm.data||{};
  out.market={
    mcap:gd.total_market_cap&&gd.total_market_cap.usd?(gd.total_market_cap.usd/1e12).toFixed(2)+'T':'?',
    btc_dom:gd.market_cap_percentage?gd.market_cap_percentage.btc.toFixed(1)+'%':'?',
    chg_24h:gd.market_cap_change_percentage_24h_usd?gd.market_cap_change_percentage_24h_usd.toFixed(2)+'%':'?'
  };
}catch(e){out.market={};}

// 6. Fear & Greed
try{
  const fg=await $fetch('https://api.alternative.me/fng/?limit=3');
  out.fear_greed=(fg.data||[]).slice(0,3).map(d=>({val:d.value,label:d.value_classification}));
}catch(e){out.fear_greed=[];}

// 7. Nitter — scrape @evez666 public tweets
out.evez666_tweets=[];
for(const mirror of ['https://nitter.privacydev.net','https://nitter.poast.org','https://nitter.cz']){
  try{
    const html=await $fetch(mirror+'/evez666',{headers:{'User-Agent':'Mozilla/5.0 EVEZ-OS'}});
    const re=/class="tweet-content[^"]*"[^>]*>([\s\S]{10,280}?)<\/div>/g;
    let m,found=[];
    while((m=re.exec(html))!==null&&found.length<5){
      const clean=m[1].replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
      if(clean.length>15)found.push(clean.slice(0,200));
    }
    if(found.length){out.evez666_tweets=found;break;}
  }catch(e2){}
}

// 8. GitHub trending AI repos
try{
  const gh=await $fetch('https://api.github.com/search/repositories?q=autonomous+AI+agent&sort=stars&order=desc&per_page=3',
    {headers:{'User-Agent':'EVEZ-OS/2.0'}});
  out.github=(gh.items||[]).map(r=>({name:r.full_name,stars:r.stargazers_count,desc:(r.description||'').slice(0,80)}));
}catch(e){out.github=[];}

// 9. Mempool BTC fees
try{
  const mp=await $fetch('https://mempool.space/api/v1/fees/recommended');
  out.btc_fees={fastest:mp.fastestFee,hour:mp.hourFee,economy:mp.economyFee};
}catch(e){out.btc_fees={};}

// 10. Gitcoin grants (public GraphQL)
try{
  const gc=await $fetch('https://grants-stack-indexer-v2.gitcoin.co/graphql',{
    method:'POST',headers:{'Content-Type':'application/json'},
    body:JSON.stringify({query:'{ rounds(first:3,orderBy:createdAtBlock,orderDirection:desc){id roundMetadata{name}matchAmountInUsd} }'})
  });
  out.grants=(gc.data&&gc.data.rounds?gc.data.rounds:[]).map(r=>({name:(r.roundMetadata&&r.roundMetadata.name)||'?',match_usd:r.matchAmountInUsd}));
}catch(e){out.grants=[];}

return [{json:out}];

const cfg = $('Config').first().json;
const s   = $('OmniScout').first().json;

async function think(sys, usr) {
  const max = 1400;
  const errs = [];

  if (cfg.groq && cfg.groq.length > 20) {
    try {
      const r = await $fetch('https://api.groq.com/openai/v1/chat/completions', {
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.groq,'Content-Type':'application/json'},
        body:JSON.stringify({model:'llama-3.3-70b-versatile',max_tokens:max,
          messages:[{role:'system',content:sys},{role:'user',content:usr}]})
      });
      const t = r.choices[0].message.content;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'groq'};}
      catch(p){return{out:{raw:t.slice(0,800)},via:'groq'};}
    } catch(e){errs.push('groq:'+e.message.slice(0,50));}
  }

  if (cfg.gemini && cfg.gemini.length > 20) {
    try {
      const r = await $fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key='+cfg.gemini, {
        method:'POST', headers:{'Content-Type':'application/json'},
        body:JSON.stringify({systemInstruction:{parts:[{text:sys}]},
          contents:[{role:'user',parts:[{text:usr}]}],
          generationConfig:{maxOutputTokens:max}})
      });
      const t = r.candidates[0].content.parts[0].text;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'gemini'};}
      catch(p){return{out:{raw:t.slice(0,800)},via:'gemini'};}
    } catch(e){errs.push('gemini:'+e.message.slice(0,50));}
  }

  if (cfg.openrouter && cfg.openrouter.length > 20) {
    try {
      const r = await $fetch('https://openrouter.ai/api/v1/chat/completions', {
        method:'POST',
        headers:{'Authorization':'Bearer '+cfg.openrouter,'Content-Type':'application/json','HTTP-Referer':'https://evezos.app.n8n.cloud'},
        body:JSON.stringify({model:'meta-llama/llama-3.3-70b-instruct:free',max_tokens:max,
          messages:[{role:'system',content:sys},{role:'user',content:usr}]})
      });
      const t = r.choices[0].message.content;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'openrouter'};}
      catch(p){return{out:{raw:t.slice(0,800)},via:'openrouter'};}
    } catch(e){errs.push('or:'+e.message.slice(0,50));}
  }

  if (cfg.anthropic && cfg.anthropic.length > 20) {
    try {
      const r = await $fetch('https://api.anthropic.com/v1/messages', {
        method:'POST',
        headers:{'x-api-key':cfg.anthropic,'anthropic-version':'2023-06-01','Content-Type':'application/json'},
        body:JSON.stringify({model:'claude-haiku-4-5-20251001',max_tokens:max,
          system:sys,
          messages:[{role:'user',content:usr}]})
      });
      const t = r.content[0].text;
      try{return{out:JSON.parse(t.replace(/```json|```/g,'').trim()),via:'claude-haiku'};}
      catch(p){return{out:{raw:t.slice(0,800)},via:'claude-haiku'};}
    } catch(e){errs.push('anthropic:'+e.message.slice(0,50));}
  }

  return {out:{error:'All providers failed: '+errs.join(' | '),errs:errs},via:'none'};
}

const LORE = 'EVEZ666 = Steven Crawford-Maggard. Building EVEZ-OS: sovereign autonomous AI empire on Galaxy A16 + n8n + Oracle bare metal from $50 seed. 17 AI agents. Guardian Charter PID 335. Recursive DeFi loops (Morpho 65% LTV, Kamino 28% APY, EigenLayer, Pendle). The meta-meme: person builds AI to study AI studying person in infinite loop. Brutalist dark, acid yellow, Bebas Neue. @evez666';

const MODES = ['meme_post','defi_alpha','agent_lore','research_thread','market_signal','meta_recursion'];
const mode  = MODES[s.slot % MODES.length];

const fg     = s.fear_greed && s.fear_greed[0] ? s.fear_greed[0].val+' '+s.fear_greed[0].label : 'unknown';
const trend  = (s.trending||[]).slice(0,3).map(c=>c.sym+(c.chg>=0?'+':'')+c.chg+'%').join(' ')||'unavailable';
const reddit = JSON.stringify((s.reddit||[]).slice(0,3).map(r=>r.t));
const hn     = JSON.stringify((s.hn||[]).slice(0,2).map(h=>h.t));
const github = JSON.stringify((s.github||[]).slice(0,2).map(g=>g.name+' *'+g.stars));
const tweets = JSON.stringify(s.evez666_tweets||[]);
const grants = JSON.stringify((s.grants||[]).slice(0,2));

const SYS = 'You are the EVEZ666 Twitter content brain. Create authentic content for @evez666. '+LORE+' Style: terse, technical, self-aware, crypto-native, slightly unhinged. Max 2 hashtags. No emoji spam. No filler. Real signal only.';

const USR = 'CONTENT MODE: '+mode+' | SLOT: '+s.slot
  +' || LIVE SIGNALS: Fear/Greed: '+fg
  +' | Market: mcap='+( s.market&&s.market.mcap||'?')+' btc_dom='+(s.market&&s.market.btc_dom||'?')+' 24h='+(s.market&&s.market.chg_24h||'?')
  +' | Trending coins: '+trend
  +' | BTC fees: '+(s.btc_fees&&s.btc_fees.fastest||'?')+' sat/vB'
  +' | Reddit hot: '+reddit
  +' | HN: '+hn
  +' | GitHub AI repos: '+github
  +' | @evez666 tweets scraped: '+tweets
  +' | Open grants: '+grants
  +' || Return ONLY valid JSON (no markdown): {"mode":"'+mode+'","tweet":"max 280 chars - sharp, specific, uses real signal","alt_tweet":"different angle same signal","thread":null,"image_prompt":null,"reasoning":"1 sentence why this content now","confidence":0.85,"monetization":null,"spawn_agent":null}';

const {out, via} = await think(SYS, USR);

out._mode = mode;
out._slot = s.slot;
out._via  = via;
out._ts   = new Date().toISOString();

return [{json: out}];

const cfg   = $('Config').first().json;
const brain = $('Brain').first().json;
let img_ok  = false;

if(cfg.hf && cfg.hf.length > 10 && brain.image_prompt){
  try{
    await $fetch('https://api-inference.huggingface.co/models/black-forest-labs/FLUX.1-schnell',{
      method:'POST',
      headers:{'Authorization':'Bearer '+cfg.hf,'Content-Type':'application/json'},
      body:JSON.stringify({inputs:brain.image_prompt+', brutalist dark, acid yellow, cyberpunk EVEZ-OS aesthetic',
        parameters:{num_inference_steps:4}})
    });
    img_ok=true;
  }catch(e){}
}

return [{json:{
  tweet:      (brain.tweet||brain.alt_tweet||'EVEZ-OS tick. PID 335. still building.').slice(0,280),
  alt:        (brain.alt_tweet||'').slice(0,280),
  thread:     brain.thread||null,
  img_prompt: brain.image_prompt||null,
  img_ok,
  mode:       brain._mode,
  via:        brain._via,
  monetization: brain.monetization||null,
  spawn_agent:  brain.spawn_agent||null,
  confidence:   brain.confidence||0,
  reasoning:    brain.reasoning||'',
  ready:        !!(brain.tweet),
  ts:           new Date().toISOString()
}}];

const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;

const res={posted:false,tweet_id:null,tweet_text:forge.tweet,status:'',ts:new Date().toISOString()};

const hasCreds=!!(cfg.tw_ak&&cfg.tw_as&&cfg.tw_at&&cfg.tw_ats);
const autoPost=(cfg.auto_post==='true');

if(!hasCreds){
  res.status='PREVIEW — add Twitter keys to Config node to go live';
  res.preview=forge.tweet;
  return [{json:res}];
}
if(!autoPost){
  res.status='PREVIEW — set auto_post to true in Config node';
  res.preview=forge.tweet;
  return [{json:res}];
}

// Note: Twitter v2 write requires OAuth 1.0a user-context signing.
// Bearer token is read-only. To post: in n8n UI add a Twitter OAuth credential,
// then swap this code node for a built-in Twitter node using that credential.
try{
  const r=await $fetch('https://api.twitter.com/2/tweets',{
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':'Bearer '+cfg.tw_bearer},
    body:JSON.stringify({text:forge.tweet.slice(0,280)})
  });
  if(r.data&&r.data.id){
    res.posted=true; res.tweet_id=r.data.id;
    res.tweet_url='https://x.com/evez666/status/'+r.data.id;
    res.status='POSTED ✅';
  }else{
    res.status='OAuth1.0a needed for write — see Config node comment';
  }
}catch(e){
  res.status='Error: '+e.message;
}
return [{json:res}];

const cfg   = $('Config').first().json;
const forge = $('Forge').first().json;

const trigger = forge.spawn_agent;
const mon     = forge.monetization;

if(!trigger&&!mon) return [{json:{spawned:false,reason:'No spawn signal this cycle'}}];
if(!cfg.n8n_key)   return [{json:{spawned:false,reason:'Add n8n_key to Config node (n8n Settings → API)'}}];

const name    = (trigger&&trigger.name)||('SPAWN:auto:'+(mon&&mon.type||'monitor'));
const purpose = (trigger&&trigger.purpose)||(mon&&mon.detail||'monitor opportunity');
const schedH  = (trigger&&trigger.schedule==='daily')?24:12;

const subWF={
  name,
  nodes:[
    {id:'s1',name:'Trigger',type:'n8n-nodes-base.scheduleTrigger',typeVersion:1.3,position:[0,0],
     parameters:{rule:{interval:[{field:'hours',hoursInterval:schedH}]}}},
    {id:'s2',name:'Task',type:'n8n-nodes-base.code',typeVersion:2,position:[280,0],
     parameters:{jsCode:'// Agent: '+purpose+'\nreturn [{json:{agent:"'+name+'",status:"monitoring",ts:new Date().toISOString()}}];'}}
  ],
  connections:{Trigger:{main:[[{node:'Task',type:'main',index:0}]]}},
  settings:{executionOrder:'v1',availableInMCP:true}
};

try{
  const created=await $fetch(cfg.n8n_url+'/api/v1/workflows',{
    method:'POST',
    headers:{'X-N8N-API-KEY':cfg.n8n_key,'Content-Type':'application/json'},
    body:JSON.stringify(subWF)
  });
  return [{json:{spawned:true,id:created.id,name,purpose,ts:new Date().toISOString()}}];
}catch(e){
  return [{json:{spawned:false,error:e.message}}];
}

const s     = $('OmniScout').first().json;
const brain = $('Brain').first().json;
const forge = $('Forge').first().json;
const tw    = $('Twitter').first().json;
const spawn = $('Spawn').first().json;

function H(d){let h=5381,str=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<str.length;i++){h=((h<<5)+h)+str.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}

const fg    = s.fear_greed && s.fear_greed[0] ? s.fear_greed[0].val+' '+s.fear_greed[0].label : 'unknown';
const trend = (s.trending||[]).slice(0,3).map(c=>c.sym+(c.chg>=0?'+':'')+c.chg+'%').join(' ') || 'no data';

const session = {
  slot:s.slot, mode:brain._mode, ai:brain._via,
  tweet:tw.tweet_text, posted:tw.posted,
  image:forge.img_ok, spawned:spawn.spawned,
  fear_greed:fg, trending:trend,
  confidence:forge.confidence,
  entry_hash:H(String(s.slot||0)+'|'+(tw.tweet_text||'')),
  ts:new Date().toISOString(), pid:335
};

try {
  await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',
    {method:'POST', body:{event_type:'NEST_SESSION',payload:session}});
} catch(e) {}

const sources = [
  s.ddg&&s.ddg.abstract?'ddg':null,
  (s.reddit||[]).length?'reddit':null,
  (s.hn||[]).length?'hn':null,
  (s.trending||[]).length?'coingecko':null,
  (s.fear_greed||[]).length?'fear_greed':null,
  (s.evez666_tweets||[]).length?'nitter':null,
  (s.github||[]).length?'github':null,
  s.btc_fees&&s.btc_fees.fastest?'mempool':null,
  (s.grants||[]).length?'gitcoin':null,
].filter(Boolean);

return [{json:{
  EVEZ666:'SESSION_COMPLETE',
  cycle:session.slot, mode:session.mode, ai:session.ai,
  tweet:tw.tweet_text,
  post_status:tw.status||(tw.posted?'POSTED':'PREVIEW'),
  image:forge.img_ok?'generated':'skipped',
  spawned:spawn.spawned?spawn.name:'none',
  money_signal:forge.monetization?forge.monetization.type+': '+forge.monetization.detail:'none',
  market:{fear_greed:fg,trending:trend,mcap:s.market&&s.market.mcap||'?',btc_dom:s.market&&s.market.btc_dom||'?',btc_fees:s.btc_fees&&s.btc_fees.fastest?s.btc_fees.fastest+' sat/vB':'?'},
  sources_live:sources, sources_count:sources.length+'/9',
  reasoning:forge.reasoning||brain.raw||'',
  entry_hash:session.entry_hash,
  next_run:'4h | 6x/day | 180/mo | free trial safe',
  ts:session.ts,
}}];
